<?php
declare(strict_types=1);
require dirname(__DIR__).'/src/bootstrap.php';require dirname(__DIR__).'/src/scheduled_reports.php';
$rows=db()->query("SELECT * FROM scheduled_reports WHERE active=1 AND next_run_at<=NOW() ORDER BY next_run_at LIMIT 50")->fetchAll();foreach($rows as $row){$errors=[];$body=scheduled_report_body($row['report_type']);$subject=app_setting('app_name','OpenCRM').' â€” '.($row['report_type']==='weekly_pipeline'?'Weekly pipeline report':'Month-end new contacts report');foreach(array_filter(array_map('trim',explode(',',$row['recipient_emails']))) as $recipient)try{crm_send_email($recipient,$subject,$body,true);}catch(Throwable $e){$errors[]=$recipient.': '.$e->getMessage();}$next=scheduled_report_next_run($row['report_type'],$row['weekday']!==null?(int)$row['weekday']:null,$row['send_time'],$row['timezone']);db()->prepare('UPDATE scheduled_reports SET last_run_at=NOW(),last_status=?,last_error=?,next_run_at=? WHERE id=?')->execute([$errors?'failed':'sent',$errors?mb_strimwidth(implode(' | ',$errors),0,1000):null,$next->format('Y-m-d H:i:s'),$row['id']]);app_log($errors?'error':'info','Scheduled report processed',['schedule_id'=>(int)$row['id'],'type'=>$row['report_type'],'errors'=>$errors]);}echo count($rows)." scheduled report(s) processed.\n";

